module top_module(
    input CLK,
    input EN,
    input TE,
    output ENCLK
);wire clk_gated;
    reg EN_reg;

    always @ (posedge CLK, posedge TE) begin
        if (TE) begin
            EN_reg <= 1'b0;
        end else begin
            EN_reg <= EN;
        end
    end

    assign clk_gated = EN_reg & CLK;
    assign ENCLK = clk_gated;

endmodule
